#include<bits/stdc++.h>
using namespace std;

int solve(vector<int> a, int n){
	int ans=0;
	sort(a.begin(), a.end());
	for(int i=0;i<n;i++){
		int start=a[i];
		int j=lower_bound(a.begin() + i, a.end(), start + n) - a.begin();
		ans=max(ans, j-i);
	}
	return n-ans;
}

int main(){
	int n;
	cin>>n;
	vector<int> a(n);
	for(int i=0;i<n;i++)cin>>a[i];
	cout<<solve(a, n)<<'\n';
}
